      styles: ["\n\n\n\n\n.app-shell[_ngcontent-%COMP%] {\n  min-height: 100vh;\n  display: flex;\n  flex-direction: column;\n}\n\n\n\n.header[_ngcontent-%COMP%] {\n  position: fixed;\n  top: 0;\n  left: 0;\n  right: 0;\n  z-index: 100;\n  padding: 0 2rem;\n  transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);\n  background: transparent;\n}\n.header.scrolled[_ngcontent-%COMP%] {\n  background: rgba(250, 246, 240, 0.85);\n  backdrop-filter: blur(20px);\n  -webkit-backdrop-filter: blur(20px);\n  border-bottom: 1px solid rgba(27, 67, 50, 0.06);\n  box-shadow: 0 1px 20px rgba(27, 67, 50, 0.05);\n}\n.header-inner[_ngcontent-%COMP%] {\n  max-width: 1360px;\n  margin: 0 auto;\n  height: 72px;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 2rem;\n}\n\n\n\n.logo[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  cursor: pointer;\n  text-decoration: none;\n  flex-shrink: 0;\n}\n.logo-img[_ngcontent-%COMP%] {\n  width: 52px;\n  height: 52px;\n  object-fit: contain;\n  transition: transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);\n}\n.logo[_ngcontent-%COMP%]:hover   .logo-img[_ngcontent-%COMP%] { transform: rotate(-8deg) scale(1.1); }\n\n\n\n.nav-desktop[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: center;\n  gap: 4px;\n}\n.nav-link[_ngcontent-%COMP%] {\n  padding: 8px 16px;\n  border: none;\n  background: transparent;\n  color: var(--mt-charcoal);\n  font-family: var(--font-display);\n  font-weight: 500;\n  font-size: 0.88rem;\n  border-radius: 999px;\n  cursor: pointer;\n  transition: all 0.25s cubic-bezier(0.16, 1, 0.3, 1);\n  position: relative;\n}\n.nav-link[_ngcontent-%COMP%]:hover {\n  background: rgba(45, 106, 79, 0.07);\n  color: var(--mt-emerald);\n}\n.nav-link.active[_ngcontent-%COMP%] {\n  background: var(--mt-forest);\n  color: white;\n}\n.nav-link.active[_ngcontent-%COMP%]:hover {\n  background: var(--mt-emerald);\n  color: white;\n}\n\n\n\n.header-actions[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n}\n.user-avatar[_ngcontent-%COMP%] {\n  width: 38px;\n  height: 38px;\n  border-radius: 50%;\n  background: linear-gradient(135deg, var(--mt-emerald), var(--mt-forest));\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: pointer;\n  font-size: 1rem;\n  transition: transform 0.3s;\n}\n.user-avatar[_ngcontent-%COMP%]:hover { transform: scale(1.1); }\n\n\n\n.hamburger[_ngcontent-%COMP%] {\n  display: none;\n  flex-direction: column;\n  justify-content: center;\n  gap: 5px;\n  width: 40px;\n  height: 40px;\n  padding: 8px;\n  background: transparent;\n  border: none;\n  cursor: pointer;\n  z-index: 101;\n}\n.hamburger[_ngcontent-%COMP%]   span[_ngcontent-%COMP%] {\n  width: 100%;\n  height: 2px;\n  background: var(--mt-forest);\n  border-radius: 2px;\n  transition: all 0.3s cubic-bezier(0.16, 1, 0.3, 1);\n  transform-origin: center;\n}\n.hamburger.open[_ngcontent-%COMP%]   span[_ngcontent-%COMP%]:nth-child(1) { transform: translateY(7px) rotate(45deg); }\n.hamburger.open[_ngcontent-%COMP%]   span[_ngcontent-%COMP%]:nth-child(2) { opacity: 0; transform: scaleX(0); }\n.hamburger.open[_ngcontent-%COMP%]   span[_ngcontent-%COMP%]:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }\n\n\n\n.mobile-menu[_ngcontent-%COMP%] {\n  position: fixed;\n  inset: 0;\n  z-index: 99;\n  background: rgba(250, 246, 240, 0.97);\n  backdrop-filter: blur(30px);\n  -webkit-backdrop-filter: blur(30px);\n  transform: translateX(100%);\n  transition: transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);\n  display: none;\n}\n.mobile-menu.open[_ngcontent-%COMP%] { transform: translateX(0); }\n.mobile-menu-inner[_ngcontent-%COMP%] {\n  padding: 100px 2rem 2rem;\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n  height: 100%;\n}\n.mobile-nav-link[_ngcontent-%COMP%] {\n  display: flex;\n  align-items: center;\n  gap: 14px;\n  padding: 16px 20px;\n  border: none;\n  background: transparent;\n  font-family: var(--font-display);\n  font-weight: 600;\n  font-size: 1.1rem;\n  color: var(--mt-charcoal);\n  border-radius: var(--radius-md);\n  cursor: pointer;\n  transition: all 0.2s;\n}\n.mobile-nav-link[_ngcontent-%COMP%]:hover, .mobile-nav-link.active[_ngcontent-%COMP%] {\n  background: rgba(45, 106, 79, 0.08);\n  color: var(--mt-emerald);\n}\n.mobile-nav-link.gold[_ngcontent-%COMP%] { color: var(--mt-gold); }\n.mobile-nav-icon[_ngcontent-%COMP%] { font-size: 1.3rem; }\n.mobile-menu-footer[_ngcontent-%COMP%] {\n  margin-top: auto;\n  padding: 1.5rem 0;\n  border-top: 1px solid rgba(27, 67, 50, 0.08);\n}\n\n\n\n.main-content[_ngcontent-%COMP%] {\n  flex: 1;\n  margin-top: 72px;\n  transition: opacity 0.15s ease;\n}\n.main-content.transitioning[_ngcontent-%COMP%] {\n  opacity: 0;\n  transform: translateY(8px);\n}\n\n.view-section[_ngcontent-%COMP%] {\n  max-width: 1360px;\n  margin: 0 auto;\n  padding: 2.5rem 2rem 4rem;\n}\n\n\n\n.hero-section[_ngcontent-%COMP%] {\n  position: relative;\n  overflow: hidden;\n}\n.hero-bg[_ngcontent-%COMP%] {\n  position: absolute;\n  inset: 0;\n  z-index: 0;\n  overflow: hidden;\n}\n.hero-orb[_ngcontent-%COMP%] {\n  position: absolute;\n  border-radius: 50%;\n  filter: blur(80px);\n  opacity: 0.4;\n  animation: float 8s ease-in-out infinite;\n}\n.hero-orb-1[_ngcontent-%COMP%] {\n  width: 500px;\n  height: 500px;\n  background: radial-gradient(circle, rgba(45, 106, 79, 0.25), transparent);\n  top: -100px;\n  right: -100px;\n}\n.hero-orb-2[_ngcontent-%COMP%] {\n  width: 400px;\n  height: 400px;\n  background: radial-gradient(circle, rgba(212, 160, 23, 0.2), transparent);\n  bottom: -50px;\n  left: -80px;\n  animation-delay: 3s;\n}\n.hero-orb-3[_ngcontent-%COMP%] {\n  width: 300px;\n  height: 300px;\n  background: radial-gradient(circle, rgba(45, 106, 79, 0.15), transparent);\n  top: 50%;\n  left: 50%;\n  animation-delay: 5s;\n}\n\n.hero-content[_ngcontent-%COMP%] {\n  position: relative;\n  z-index: 1;\n  max-width: 1360px;\n  margin: 0 auto;\n  padding: 5rem 2rem 4rem;\n  display: grid;\n  grid-template-columns: 1.1fr 0.9fr;\n  gap: 4rem;\n  align-items: center;\n  min-height: calc(100vh - 72px);\n}\n\n.hero-title[_ngcontent-%COMP%] {\n  font-size: clamp(2.4rem, 5vw, 3.8rem);\n  font-weight: 900;\n  color: var(--mt-forest-deep);\n  line-height: 1.08;\n  margin-bottom: 1.5rem;\n  letter-spacing: -0.03em;\n}\n.text-gradient[_ngcontent-%COMP%] {\n  background: linear-gradient(135deg, var(--mt-emerald) 0%, var(--mt-gold) 100%);\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n}\n.hero-subtitle[_ngcontent-%COMP%] {\n  font-size: 1.15rem;\n  color: var(--mt-grey-warm);\n  line-height: 1.7;\n  margin-bottom: 2.5rem;\n  max-width: 520px;\n}\n\n\n\n.search-box[_ngcontent-%COMP%] {\n  display: flex;\n  gap: 12px;\n  max-width: 560px;\n}\n.search-input-wrap[_ngcontent-%COMP%] {\n  flex: 1;\n  position: relative;\n}\n.search-icon[_ngcontent-%COMP%] {\n  position: absolute;\n  left: 16px;\n  top: 50%;\n  transform: translateY(-50%);\n  font-size: 1.1rem;\n  opacity: 0.5;\n}\n.search-input[_ngcontent-%COMP%] {\n  width: 100%;\n  padding: 16px 20px 16px 44px;\n  border: 2px solid rgba(27, 67, 50, 0.1);\n  border-radius: var(--radius-lg);\n  font-family: var(--font-body);\n  font-size: 0.95rem;\n  background: rgba(255, 255, 255, 0.8);\n  backdrop-filter: blur(10px);\n  transition: all 0.3s;\n  outline: none;\n  color: var(--mt-charcoal);\n}\n.search-input[_ngcontent-%COMP%]:focus {\n  border-color: var(--mt-emerald);\n  box-shadow: 0 0 0 4px rgba(45, 106, 79, 0.08);\n  background: white;\n}\n.search-btn[_ngcontent-%COMP%] { flex-shrink: 0; white-space: nowrap; }\n.error-msg[_ngcontent-%COMP%] {\n  margin-top: 1rem;\n  color: var(--mt-red);\n  font-weight: 500;\n  font-size: 0.9rem;\n}\n\n\n\n.hero-right[_ngcontent-%COMP%] {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n.hero-visual[_ngcontent-%COMP%] {\n  position: relative;\n  width: 100%;\n  max-width: 420px;\n}\n.hero-logo-float[_ngcontent-%COMP%] {\n  width: 220px;\n  height: 220px;\n  object-fit: contain;\n  display: block;\n  margin: 0 auto 2rem;\n  animation: float 6s ease-in-out infinite;\n  filter: drop-shadow(0 20px 40px rgba(27, 67, 50, 0.15));\n}\n.hero-stat-cards[_ngcontent-%COMP%] {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 12px;\n}\n.stat-mini-card[_ngcontent-%COMP%] {\n  background: rgba(255, 255, 255, 0.7);\n  backdrop-filter: blur(16px);\n  border: 1px solid rgba(255, 255, 255, 0.5);\n  border-radius: var(--radius-md);\n  padding: 16px 12px;\n  text-align: center;\n  box-shadow: var(--shadow-sm);\n  transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);\n}\n.stat-mini-card[_ngcontent-%COMP%]:hover { transform: translateY(-4px); }\n.stat-mini-value[_ngcontent-%COMP%] {\n  display: block;\n  font-family: var(--font-display);\n  font-weight: 800;\n  font-size: 1.3rem;\n}\n.stat-mini-label[_ngcontent-%COMP%] {\n  display: block;\n  font-size: 0.7rem;\n  color: var(--mt-grey-warm);\n  margin-top: 4px;\n  font-weight: 500;\n}\n\n\n\n.result-card[_ngcontent-%COMP%] {\n  position: relative;\n  z-index: 1;\n  max-width: 1360px;\n  margin: -2rem auto 3rem;\n  padding: 2rem 2.5rem;\n  display: flex;\n  align-items: center;\n  gap: 1.5rem;\n  background: white;\n  border-radius: var(--radius-xl);\n  box-shadow: var(--shadow-lg);\n  border-left: 6px solid var(--mt-grey-warm);\n}\n.result-card.verdict-green[_ngcontent-%COMP%] { border-left-color: var(--mt-emerald); }\n.result-card.verdict-red[_ngcontent-%COMP%] { border-left-color: var(--mt-red); }\n.result-card.verdict-yellow[_ngcontent-%COMP%] { border-left-color: var(--mt-gold); }\n.result-card.verdict-pending[_ngcontent-%COMP%] { border-left-color: var(--mt-grey-warm); }\n.result-icon[_ngcontent-%COMP%] { font-size: 2.5rem; flex-shrink: 0; }\n.result-body[_ngcontent-%COMP%] { flex: 1; }\n.result-body[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%] {\n  font-family: var(--font-display);\n  font-size: 1.1rem;\n  margin-bottom: 4px;\n}\n.result-title-num[_ngcontent-%COMP%] { font-weight: 600; font-size: 0.9rem; }\n.result-message[_ngcontent-%COMP%] { color: var(--mt-grey-warm); font-size: 0.9rem; margin: 4px 0; }\n.result-date[_ngcontent-%COMP%] { font-size: 0.75rem; color: var(--mt-grey-warm); }\n\n\n\n.pillars-section[_ngcontent-%COMP%] {\n  position: relative;\n  z-index: 1;\n  max-width: 1360px;\n  margin: 0 auto;\n  padding: 2rem 2rem 5rem;\n}\n.section-title-center[_ngcontent-%COMP%] {\n  text-align: center;\n  font-size: clamp(1.5rem, 3vw, 2rem);\n  color: var(--mt-forest);\n  margin-bottom: 2.5rem;\n}\n.pillars-grid[_ngcontent-%COMP%] {\n  display: grid;\n  grid-template-columns: repeat(4, 1fr);\n  gap: 1.25rem;\n}\n.pillar-card[_ngcontent-%COMP%] {\n  background: rgba(255, 255, 255, 0.65);\n  backdrop-filter: blur(16px);\n  border: 1px solid rgba(255, 255, 255, 0.5);\n  border-radius: var(--radius-lg);\n  padding: 2rem 1.5rem;\n  cursor: pointer;\n  transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);\n  position: relative;\n  overflow: hidden;\n}\n.pillar-card[_ngcontent-%COMP%]::after {\n  content: '';\n  position: absolute;\n  inset: 0;\n  background: linear-gradient(135deg, rgba(45, 106, 79, 0.03), rgba(212, 160, 23, 0.03));\n  opacity: 0;\n  transition: opacity 0.4s;\n}\n.pillar-card[_ngcontent-%COMP%]:hover {\n  transform: translateY(-6px);\n  box-shadow: var(--shadow-lg);\n  border-color: rgba(45, 106, 79, 0.15);\n}\n.pillar-card[_ngcontent-%COMP%]:hover::after { opacity: 1; }\n.pillar-icon[_ngcontent-%COMP%] {\n  font-size: 2rem;\n  margin-bottom: 1rem;\n}\n.pillar-card[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%] {\n  font-family: var(--font-display);\n  font-size: 1.15rem;\n  color: var(--mt-forest);\n  margin-bottom: 0.5rem;\n}\n.pillar-card[_ngcontent-%COMP%]   p[_ngcontent-%COMP%] {\n  font-size: 0.85rem;\n  color: var(--mt-grey-warm);\n  line-height: 1.5;\n}\n.pillar-arrow[_ngcontent-%COMP%] {\n  position: absolute;\n  bottom: 1.5rem;\n  right: 1.5rem;\n  font-size: 1.2rem;\n  color: var(--mt-emerald);\n  opacity: 0;\n  transform: translateX(-8px);\n  transition: all 0.3s cubic-bezier(0.16, 1, 0.3, 1);\n}\n.pillar-card[_ngcontent-%COMP%]:hover   .pillar-arrow[_ngcontent-%COMP%] {\n  opacity: 1;\n  transform: translateX(0);\n}\n\n\n\n.footer[_ngcontent-%COMP%] {\n  background: var(--mt-forest-deep);\n  color: rgba(255, 255, 255, 0.6);\n  padding: 3rem 2rem 2rem;\n  margin-top: auto;\n}\n.footer-inner[_ngcontent-%COMP%] {\n  max-width: 1360px;\n  margin: 0 auto;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 1.5rem;\n}\n.footer-logo[_ngcontent-%COMP%] {\n  width: 48px;\n  height: 48px;\n  object-fit: contain;\n  filter: brightness(1.3);\n}\n.footer-tagline[_ngcontent-%COMP%] {\n  font-family: var(--font-display);\n  font-weight: 600;\n  color: var(--mt-gold);\n  font-size: 0.9rem;\n  margin-top: 6px;\n}\n.footer-brand[_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n}\n.footer-links[_ngcontent-%COMP%] {\n  display: flex;\n  gap: 2rem;\n}\n.footer-links[_ngcontent-%COMP%]   a[_ngcontent-%COMP%] {\n  color: rgba(255, 255, 255, 0.5);\n  font-size: 0.85rem;\n  font-weight: 500;\n  cursor: pointer;\n  transition: color 0.3s;\n}\n.footer-links[_ngcontent-%COMP%]   a[_ngcontent-%COMP%]:hover { color: var(--mt-gold); }\n.footer-copy[_ngcontent-%COMP%] {\n  font-size: 0.75rem;\n  padding-top: 1.5rem;\n  border-top: 1px solid rgba(255, 255, 255, 0.06);\n  width: 100%;\n  text-align: center;\n}\n\n\n\n@media (max-width: 1024px) {\n  .pillars-grid[_ngcontent-%COMP%] { grid-template-columns: repeat(2, 1fr); }\n  .hero-content[_ngcontent-%COMP%] { grid-template-columns: 1fr; gap: 2rem; }\n  .hero-right[_ngcontent-%COMP%] { display: none; }\n  .hero-content[_ngcontent-%COMP%] { min-height: auto; padding: 3rem 2rem; }\n}\n\n@media (max-width: 768px) {\n  .header[_ngcontent-%COMP%] { padding: 0 1rem; }\n  .nav-desktop[_ngconten